arguments.command:
curl -s 'https://hnrss.org/frontpage' | python3 -c "import sys,xml.etree.ElementTree as ET; root=ET.parse(sys.stdin).getroot(); items=root.findall('.//item')[:15]; targets=[0,1,6]; [print(f'### {items[i].find("title").text}
URL: {items[i].find("link").text}
Comments: {items[i].find("comments").text if items[i].find("comments") is not None else "N/A"}
Description: {(items[i].find("description").text or "")[:300]}
') for i in targets]"
